SELECT AVG(mean) AS average_mean
FROM performance_metrics
WHERE category = 'Request';

SELECT AVG(average_value) AS avg_average_value
FROM performance_trends
WHERE app_id = 1;

SELECT AVG(value) AS mean_wave_height
FROM performance_data
WHERE metric_id = 1;

SELECT AVG(value) AS average_hits
FROM performance_data
WHERE metric_id = (SELECT metric_id FROM performance_metrics WHERE metric_name = 'Hits');

SELECT metric_name
FROM performance_metrics
WHERE metric_id = 1;

SELECT MAX(value) AS max_hits
FROM performance_data
WHERE metric_id = (SELECT metric_id FROM performance_metrics WHERE metric_name = 'Hits');
